31		// Handle flags by calling pure business logic functions
32		if showFlag {
33			return fmt.Errorf("config show removed - use 'cat .ddx/config.yaml' to view configuration")
34		}
35	
36		if showFilesFlag {
37			files := configListFiles(f.WorkingDir)
38			return f.outputConfigFiles(cmd, files)
39		}
40	
41		if editFlag {
42			configPath := configGetPath(f.WorkingDir, globalFlag)
43			return f.editConfigFile(cmd, configPath)
44		}
45	
46		if resetFlag {
47			configPath := configGetPath(f.WorkingDir, globalFlag)
48			if err := configReset(f.WorkingDir, globalFlag); err != nil {
49				return err
50			}
51			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Configuration reset to defaults: %s\n", configPath)
52			return nil
53		}
54	
55		if wizardFlag {
56			cfg, err := configWizard()
57			if err != nil {
58				return err
59			}
60			if err := configSave(f.WorkingDir, cfg, false); err != nil {
61				return err
62			}
63			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "✅ Configuration saved to .ddx/config.yaml")
64			return nil
65		}
66	
67		if validateFlag {
68			if err := configValidate(f.WorkingDir); err != nil {
69				return err
70			}
71			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "✅ Configuration is valid")
72			return nil
73		}
74	
75		// Handle subcommands
76		if len(args) == 0 {
77			// Default behavior: show help
78			return cmd.Help()
79		}
80	
81		subcommand := args[0]
82		switch subcommand {
83		case "get":
84			if len(args) < 2 {
85				return fmt.Errorf("key required for get command")
86			}
87			value, err := configGet(f.WorkingDir, args[1], globalFlag)
88			if err != nil {
89				return err
90			}
91			_, _ = fmt.Fprintln(cmd.OutOrStdout(), value)
92			return nil
93		case "set":
94			if len(args) < 3 {
95				return fmt.Errorf("key and value required for set command")
96			}
97			if err := configSet(f.WorkingDir, args[1], args[2], globalFlag); err != nil {
98				return err
99			}
100			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Set %s = %s\n", args[1], args[2])
101			return nil
102		case "validate":
103			if err := configValidate(f.WorkingDir); err != nil {
104				return err
105			}
106			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "✅ Configuration is valid")
107			return nil
108		case "export":
109			// Simply output the config file content
110			var configPath string
111			if globalFlag {
112				// Use global config path
113				homeDir, err := os.UserHomeDir()
114				if err != nil {
115					return fmt.Errorf("failed to get home directory: %w", err)
116				}
117				configPath = filepath.Join(homeDir, ".ddx", "config.yaml")
118			} else {
119				// Use local config path
