461	// handleProfileSubcommand handles profile-specific subcommands for US-023
462	func handleProfileSubcommand(cmd *cobra.Command, args []string) error {
463		if len(args) == 0 {
464			return fmt.Errorf("profile subcommand requires an action")
465		}
466	
467		action := args[0]
468		switch action {
469		case "create":
470			if len(args) < 2 {
471				return fmt.Errorf("profile create requires a profile name")
472			}
473			return createProfile(cmd, args[1])
474		case "list":
475			return listProfiles(cmd)
476		case "activate":
477			if len(args) < 2 {
478				return fmt.Errorf("profile activate requires a profile name")
479			}
480			return activateProfile(cmd, args[1])
481		case "copy":
482			if len(args) < 3 {
483				return fmt.Errorf("profile copy requires source and destination profile names")
484			}
485			return copyProfile(cmd, args[1], args[2])
486		case "validate":
487			if len(args) < 2 {
488				return fmt.Errorf("profile validate requires a profile name")
489			}
490			return validateProfile(cmd, args[1])
491		case "show":
492			if len(args) < 2 {
493				return fmt.Errorf("profile show requires a profile name")
494			}
495			return showProfile(cmd, args[1])
496		case "diff":
497			if len(args) < 3 {
498				return fmt.Errorf("profile diff requires two profile names")
499			}
500			return diffProfiles(cmd, args[1], args[2])
501		case "delete":
502			if len(args) < 2 {
503				return fmt.Errorf("profile delete requires a profile name")
504			}
505			return deleteProfile(cmd, args[1])
506		default:
507			return fmt.Errorf("unknown profile action: %s", action)
508		}
509	}
