576	func ensureProjectGitignoreRules(workingDir string, rules []string) error {
577		if len(rules) == 0 {
578			return nil
579		}
580		path := filepath.Join(workingDir, ".gitignore")
581		var content string
582		if raw, err := os.ReadFile(path); err == nil {
583			content = string(raw)
584		} else if !os.IsNotExist(err) {
585			return err
586		}
587	
588		trimmed := strings.TrimRight(content, "\n")
589		var missing []string
590		for _, rule := range rules {
591			rule = strings.TrimSpace(rule)
592			if rule == "" || containsExactLine(trimmed, rule) {
593				continue
594			}
595			missing = append(missing, rule)
596		}
597		if len(missing) == 0 {
598			return nil
599		}
600	
601		updated := trimmed
602		if updated != "" {
603			updated += "\n"
604		}
605		updated += "# DDx runtime scratch\n"
606		for _, rule := range missing {
607			updated += rule + "\n"
608		}
609		return os.WriteFile(path, []byte(updated), 0o644)
610	}
